const fs   = require('fs');
const path = require('path');

const cachePath = '/home/node/.n8n/chatwoot-cache.json';

// ── Cache missing ─────────────────────────────────────────────
if (!fs.existsSync(cachePath)) {
  return [{ json: {
    _cacheStatus: 'missing',
    _cacheError:  'Cache file not found. The Collector workflow has not run yet. Activate it and run it once manually.',
    cachedAt:     null,
    nextRefresh:  null,
    ageMinutes:   null
  }}];
}

// ── Read file ─────────────────────────────────────────────────
let parsed;
try {
  const raw = fs.readFileSync(cachePath, 'utf8');
  parsed    = JSON.parse(raw);
} catch (e) {
  return [{ json: {
    _cacheStatus: 'corrupt',
    _cacheError:  'Cache file could not be parsed: ' + e.message,
    cachedAt: null, nextRefresh: null, ageMinutes: null
  }}];
}

// ── Age check ─────────────────────────────────────────────────
const cachedAt   = new Date(parsed.cachedAt);
const ageMs      = Date.now() - cachedAt.getTime();
const ageMinutes = Math.floor(ageMs / 60000);
const isStale    = ageMs > 2 * 60 * 60 * 1000; // warn if >2 hours old

// ── Return cache + metadata ───────────────────────────────────
return [{ json: {
  ...parsed.data,
  _cache: {
    status:      isStale ? 'stale' : 'fresh',
    cachedAt:    parsed.cachedAt,
    nextRefresh: parsed.nextRefresh,
    ageMinutes
  }
}}];
